def verify(output: str):
    # Input validation: ensure it's a string of exactly 700 digits
    if not isinstance(output, str):
        return (False, 0.0, "Output is not a string.")
    if len(output) != 700:
        return (False, 0.0, f"Length is {len(output)}, expected 700.")
    if not output.isdigit():
        return (False, 0.0, "Output contains non-digit characters.")

    # Initialize counter for satisfied constraints
    constraints_satisfied = 0
    total_constraints = 8
    failed_constraints = []

    # Count digit frequencies
    digit_counts = {str(d): 0 for d in range(10)}
    for ch in output:
        digit_counts[ch] += 1

    # Check constraint 1: number of digit 8 is prime
    count_8 = digit_counts['8']
    if count_8 < 2:
        is_prime_8 = False
    else:
        is_prime_8 = all(count_8 % i != 0 for i in range(2, int(count_8**0.5) + 1))
    if is_prime_8:
        constraints_satisfied += 1
    else:
        failed_constraints.append("number of digit 8 is prime")

    # Check constraint 2: number of digit 3 is exactly 3× the number of digit 6
    count_3 = digit_counts['3']
    count_6 = digit_counts['6']
    if count_3 == 3 * count_6:
        constraints_satisfied += 1
    else:
        failed_constraints.append("number of digit 3 == 3 × number of digit 6")

    # Check constraint 3: number of digit 4 is a multiple of 8
    count_4 = digit_counts['4']
    if count_4 % 8 == 0:
        constraints_satisfied += 1
    else:
        failed_constraints.append("number of digit 4 is a multiple of 8")

    # Check constraint 4: total number of even digits (0,2,4,6,8) is exactly 400
    even_digits = ['0', '2', '4', '6', '8']
    even_count = sum(digit_counts[d] for d in even_digits)
    if even_count == 400:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"total even digits = {even_count}, expected 400")

    # Check constraint 5: exactly 12 occurrences of substring "2026", non-overlapping, no others
    # Count non-overlapping occurrences of "2026"
    count_2026 = 0
    idx = 0
    while idx <= len(output) - 4:
        if output[idx:idx+4] == "2026":
            count_2026 += 1
            idx += 4  # skip to avoid overlapping matches
        else:
            idx += 1

    # Also check for any additional overlapping occurrences beyond what the non-overlapping counting found?
    # But the spec says "overlaps not allowed" and "no other occurrence besides those 12"
    # So we interpret: total occurrences (including overlapping) must be exactly 12.
    # However, the phrase "overlaps not allowed" likely means that only non-overlapping occurrences count,
    # but the phrase "no other occurrence of 2026 besides those 12" suggests all occurrences (including potential overlapping ones) must be exactly 12.
    # To be safe, count ALL occurrences (including overlapping ones) and require exactly 12.
    count_2026_all = 0
    for i in range(len(output) - 3):
        if output[i:i+4] == "2026":
            count_2026_all += 1

    if count_2026_all == 12:
        constraints_satisfied += 1
    else:
        failed_constraints.append(f"occurrences of '2026' = {count_2026_all}, expected 12")

    # Check constraint 6: no occurrence of "000"
    has_000 = "000" in output
    if not has_000:
        constraints_satisfied += 1
    else:
        failed_constraints.append("contains '000'")

    # Check constraint 7: string does not start with '0' and ends with an odd digit
    starts_with_zero = output[0] == '0'
    ends_with_odd = output[-1] in '13579'
    if not starts_with_zero and ends_with_odd:
        constraints_satisfied += 1
    else:
        reason = []
        if starts_with_zero:
            reason.append("starts with '0'")
        if not ends_with_odd:
            reason.append(f"ends with '{output[-1]}' (not odd)")
        failed_constraints.append(" and ".join(reason))

    # Check constraint 8: every digit appears at least 7 times
    min_digit_count = min(digit_counts.values())
    if min_digit_count >= 7:
        constraints_satisfied += 1
    else:
        # find which digits fail
        failing_digits = [d for d in digit_counts if digit_counts[d] < 7]
        failed_constraints.append(f"digit(s) appear < 7 times: {failing_digits}")

    # Calculate final score
    score = constraints_satisfied / total_constraints
    is_valid = (constraints_satisfied == total_constraints)

    # Generate message
    if is_valid:
        message = "All constraints satisfied."
    else:
        message = "Failed constraints: " + "; ".join(failed_constraints)

    return (is_valid, score, message)
